const gptOutput = $input.first().json.output;
const config = $('2. Set — Config Values').item.json;

if (!gptOutput || !gptOutput.youtube || !gptOutput.reels || !gptOutput.tiktok) {
  throw new Error('GPT did not return all 3 scripts. Check your OpenAI credential.');
}

const platforms = [
  {
    platform: 'YouTube',
    scriptLength: 'Long form (8 to 10 min)',
    hook: gptOutput.youtube.hook,
    script: gptOutput.youtube.script,
    cta: gptOutput.youtube.cta,
    tags: (gptOutput.youtube.tags || []).join(' ')
  },
  {
    platform: 'Instagram Reels',
    scriptLength: 'Short form (60 sec)',
    hook: gptOutput.reels.hook,
    script: gptOutput.reels.script,
    cta: gptOutput.reels.cta,
    tags: (gptOutput.reels.tags || []).join(' ')
  },
  {
    platform: 'TikTok',
    scriptLength: 'Short form (30 sec)',
    hook: gptOutput.tiktok.hook,
    script: gptOutput.tiktok.script,
    cta: gptOutput.tiktok.cta,
    tags: (gptOutput.tiktok.tags || []).join(' ')
  }
];

return platforms.map((p, index) => ({
  json: {
    today: config.today,
    videoTopic: config.videoTopic,
    platform: p.platform,
    scriptLength: p.scriptLength,
    hook: p.hook,
    script: p.script,
    cta: p.cta,
    tags: p.tags,
    submittedBy: config.submittedBy,
    isLastRow: index === 2,
    allScripts: index === 2 ? gptOutput : null,
    targetAudience: config.targetAudience,
    niche: config.niche,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    recipientEmail: config.recipientEmail,
    senderName: config.senderName
  }
}));
